"use strict";

const Constants = Object.freeze({
  /**
   * The CSS class of the annotation bubble
   * @type {String}
   */
  ANNOTATE_BUBBLE_CLASS: "annotation-bubble",
  /**
   * The name of the icon rendered in the popup
   * @type {String}
   */
  ANNOTATE_ICON_NAME: "comment",
  /**
   * The keyboard shortcut that needs to be triggered to create an annotation
   * @type {KeyboardEventInit}
   */
  ANNOTATE_SHORTCUT: { ctrlKey: true, keyCode: 77 }, // ShortcutJS still expects the deprecated keyCode property
  /**
   * The translation key for the button title (for accessibility)
   * @type {String}
   */
  ANNOTATE_TRANSLATION_KEY: "action.create.submit.text",
  /**
   * The CSS class that needs to be added to show the popup
   * @type {String}
   */
  POPUP_CLASS_OPEN: "opened",
  /**
   * The element id of the popup
   * @type {String}
   */
  POPUP_ID: "annotation-popup"
});

// Icons API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Icon%20Theme%20Application#HJavaScriptAPI)
define("xwiki-annotate-popup/icons", {
  icons: [Constants.ANNOTATE_ICON_NAME]
});

// Translation API (see: https://extensions.xwiki.org/xwiki/bin/view/Extension/Localization/#HFromJavaScript)
define("xwiki-annotate-popup/translation-keys", {
  prefix: "annotations.",
  keys: [Constants.ANNOTATE_TRANSLATION_KEY]
});

define("xwiki-annotate-popup", ["xwiki-icon!xwiki-annotate-popup/icons", "xwiki-l10n!xwiki-annotate-popup/translation-keys"], function(icons, l10n) {
   /**
    * Debounces a function
    * @param {number} delay - Delay time
    * @returns {Function} - Debounced version of func (result not returned)
    */
   function debounce(func, delay) {
      let timeout;
      return function (...args) {
          clearTimeout(timeout);
          timeout = setTimeout(() => { func.apply(this, args); }, delay);
      };
   }

   // TODO: use private class method once Google Closure Compiler supports it
   // see: https://github.com/google/closure-compiler/issues/4286
   class AnnotatePopup {
      /**
       * @param {HTMLElement} wikiContent - The XWiki page container
       */
      constructor(wikiContent) {
         this.wikiContent = wikiContent;
         this.popup = null;
         this.annotateButton = null;
         this.currentRect = null;
         this.previousFocusElem = null;

         this.onSelectionChange = debounce(this.onSelectionChange.bind(this), 700);
         this.onKeyDown = debounce(this.onKeyDown.bind(this), 60);
         this.onBlur = debounce(this.onBlur.bind(this), 60);
         this.onViewportChange = debounce(this.onViewportChange.bind(this), 150);

         this._createPopup();
         this._registerListeners();
      }

      /**
       * Inserts popup to DOM
       */
      _createPopup() {
         this.popup = document.createElement("div");
         this.popup.id = Constants.POPUP_ID;
         this.popup.setAttribute("role", "dialog");
         this.popup.setAttribute("aria-hidden", "true");

         this.popupButton = document.createElement("button");
         this.popupButton.classList.add("btn", "btn-default", "btn-xs");
         this.popupButton.title = l10n[Constants.ANNOTATE_TRANSLATION_KEY];
         this.popupButton.setAttribute("aria-label", l10n[Constants.ANNOTATE_TRANSLATION_KEY]);

         this.popupButton.appendChild(icons[Constants.ANNOTATE_ICON_NAME].render());
         this.popup.appendChild(this.popupButton);
         document.body.appendChild(this.popup);
      }

      /**
       * Register event listeners
       */
      _registerListeners() {
         // add select listener for opening popup
         document.addEventListener("selectionchange", this.onSelectionChange, { passive: true });

         // add click listener to button
         this.popupButton.addEventListener("click", () => {
            this.close();
            document.dispatchEvent(new KeyboardEvent("keydown", Constants.ANNOTATE_SHORTCUT));
         });

         // press button on Enter, close popup on Esc (listening on popup button because it is focused and popup is closed when losing focus)
         this.popupButton.addEventListener("keydown", this.onKeyDown);

         // Disable annotation popup in edit mode
         this.wikiContent.on("xwiki:actions:edit", () => { document.removeEventListener("selectionchange", this.onSelectionChange); });
         this.wikiContent.on("xwiki:actions:view", () => { document.addEventListener("selectionchange", this.onSelectionChange, { passive: true }); });

         this.popup.addEventListener("pointerdown", (event) => { event.preventDefault(); });  // prevent losing focus (the selection) when clicking on popup edges
      }

      /**
       * Checks the current selection and opens the popup
       */
      onSelectionChange() {
         this.close(); // close opened popups on new select

         const selection = window.getSelection();
         if (!selection || !this.wikiContent.contains(selection.anchorNode) || !selection.toString().trim()) {
             return;
         }

         this.open(selection);
      }

      /**
       * Keyboard navigation: Press button on Enter, close popup on Escape
       * @param {KeyboardEvent} event
       */
      onKeyDown(event) {
         if (e.key === "Enter") {
            event.preventDefault();
            this.popupButton.click();
         } else if (event.key === "Escape") {
            this.close();
            this.popupButton.removeEventListener("keydown", this.onKeyDown);

            // restore focus safely
            if (this.previousFocusElem &&
                document.contains(this.previousFocusElem) &&
                typeof this.previousFocusElem.focus === "function" &&
                !this.previousFocusElem.hasAttribute("disabled") &&
                this.previousFocusElem.getClientRects().length) {
              this.previousFocusElem.focus();
            }
         }
      }

      /**
       * Close popup on blur
       * @param {FocusEvent} event
       */
      onBlur(event) {
         if(!event.relatedTarget) {
            return;
         }

         if (!this.popup.contains(event.relatedTarget && !isClickInsideSelection)) {
            this.close();
            this.popup.removeEventListener("blur", this.onBlur);
         }
      }

      /**
       * Recalculate positioning of popup when resizing / zooming
       */
      onViewportChange(event) {
         const { top, left } = this._getPositioning(window.getSelection());
         this.popup.style.top = top;
         this.popup.style.left = left;
      }

      /**
       * Close the popup
       */
      close() {
         this.popup.classList.remove(Constants.POPUP_CLASS_OPEN);
         this.popup.setAttribute("aria-hidden", "true");

         // remove event listeners
         this.popup.removeEventListener("blur", this.onBlur);
         if(window.visualViewport) window.visualViewport.removeEventListener("resize", this.onViewportChange);
      }

      /**
       * Get popup positioning (top and left absolute positioning)
       * @param {Selection} selection - A selection
       * @return {{popupTop: number, popupLeft: number}} The popup element and popup button
       */
      _getPositioning(selection) {
         if(!selection || selection.rangeCount === 0) {
            console.debug("Could not determine popup positioning, selection range invalid");
            return;
         }

         // use last rectangle of selection, important for correct positioning in multi-line selections
         const rects = selection.getRangeAt(0).getClientRects();
         if (!rects.length) return;
         const rect = rects[rects.length - 1];

         return {
          top: (rect.top + window.scrollY - this.popup.offsetHeight - 4) + "px",
          left: (rect.left + window.scrollX + rect.width - (this.popup.offsetWidth / 2)) + "px"
         };
      }

      /**
       * Displays the popup near the selected text range
       * @param {Selection} selection - A selection
       */
      open(selection) {
         if(document.getElementsByClassName(Constants.ANNOTATE_BUBBLE_CLASS).length !== 0) {
           console.debug("Not opening annotate popup because annotate bubble is open");
           return;
         }

         const { top, left } = this._getPositioning(selection);
         this.popup.style.top = top;
         this.popup.style.left = left;

         this.popup.classList.add(Constants.POPUP_CLASS_OPEN);
         this.popup.setAttribute("aria-hidden", "false");

         // focus popup button
         this.previousFocusElem = document.activeElement;
         this.popupButton.focus();

         // add event listeners
         this.popup.addEventListener("blur", this.onBlur, { passive: true });
         if(window.visualViewport) window.visualViewport.addEventListener("resize", this.onViewportChange, { passive: true }); // re-position on viewport change
      }
   }

   return AnnotatePopup;
});

#annotation-popup {
   position: absolute;
   background-color: var(--xwiki-page-content-bg);
   padding: 4px;
   border-radius: 4px;
   box-shadow: 0 1.65px 3px var(--btn-default-border);
   visibility: hidden;
   opacity: 0;
   transition: opacity .2s ease-in;
   &.opened {
      visibility: visible;
      opacity: 1;
   }
}
